import java.util.*;
import java.lang.Math;

public class Solution {
    private static final long MOD = 1000000007L;

    public static long solve(long[] nums, long[][] queries) {
        int n = nums.length;
        int SQRT = (int) Math.sqrt(n);

        // Group queries by k (for k <= SQRT)
        @SuppressWarnings("unchecked")
        List<long[]>[] queriesByK = new List[SQRT + 1];
        for (int i = 1; i <= SQRT; i++) {
            queriesByK[i] = new ArrayList<>();
        }

        for (long[] query : queries) {
            long l = query[0];
            long r = query[1];
            long k_val = query[2];
            long v = query[3];
            if (k_val <= SQRT && k_val >= 1) {
                long residue = l % k_val;
                long t_min = (l - residue + k_val - 1) / k_val;
                long t_max = (r - residue) / k_val;
                queriesByK[(int) k_val].add(new long[]{residue, t_min, t_max, v});
            }
        }

        long[] ans_small_factor = new long[n];
        Arrays.fill(ans_small_factor, 1);

        for (int k_val = 1; k_val <= SQRT; k_val++) {
            @SuppressWarnings("unchecked")
            List<long[]>[] residues = new List[k_val];
            for (int r = 0; r < k_val; r++) {
                residues[r] = new ArrayList<>();
            }
            for (long[] qry : queriesByK[k_val]) {
                long residue = qry[0];
                long t_min = qry[1];
                long t_max = qry[2];
                long v = qry[3];
                residues[(int) residue].add(new long[]{t_min, t_max, v});
            }

            for (int residue = 0; residue < k_val; residue++) {
                if (residue >= n) continue;
                long T = (n - 1 - residue) / k_val + 1;
                if (T <= 0) continue;

                long[] diff = new long[(int) T + 1];
                Arrays.fill(diff, 1);

                for (long[] qry : residues[residue]) {
                    long t_min = qry[0];
                    long t_max_val = qry[1];
                    long v_val = qry[2];
                    if (t_min < T) {
                        diff[(int) t_min] = (diff[(int) t_min] * v_val) % MOD;
                        if (t_max_val + 1 <= T) {
                            long inv = modInv(v_val, MOD);
                            diff[(int) (t_max_val + 1)] = (diff[(int) (t_max_val + 1)] * inv) % MOD;
                        }
                    }
                }

                long[] factor_class = new long[(int) T];
                if (T > 0) {
                    factor_class[0] = diff[0];
                    for (int j = 1; j < T; j++) {
                        factor_class[j] = factor_class[j - 1] * diff[j] % MOD;
                    }
                }

                for (long j_idx = residue, t = 0; j_idx < n; j_idx += k_val, t++) {
                    if (t < T) {
                        ans_small_factor[(int) j_idx] = (ans_small_factor[(int) j_idx] * factor_class[(int) t]) % MOD;
                    }
                }
            }
        }

        long[] res = Arrays.copyOf(nums, n);
        for (int i = 0; i < n; i++) {
            res[i] = (res[i] * ans_small_factor[i]) % MOD;
        }

        for (long[] query : queries) {
            long l = query[0];
            long r = query[1];
            long k_val = query[2];
            long v = query[3];
            if (k_val > SQRT) {
                for (long j = l; j <= r; j += k_val) {
                    res[(int) j] = (res[(int) j] * v) % MOD;
                }
            }
        }

        long xor = 0;
        for (long x : res) {
            xor ^= x;
        }
        return xor;
    }

    private static long modInv(long a, long mod) {
        return pow(a, mod - 2, mod);
    }

    private static long pow(long base, long exp, long mod) {
        base %= mod;
        long res = 1;
        while (exp > 0) {
            if ((exp & 1) == 1) {
                res = (res * base) % mod;
            }
            base = (base * base) % mod;
            exp >>= 1;
        }
        return res;
    }
}
