import java.util.*;
import java.math.*;

public class Solution {
    private static final long mod = 1000000007L;

    private static int lowerBound(List<Integer> list, long target) {
        int low = 0, high = list.size();
        while (low < high) {
            int mid = (low + high) >>> 1;
            if (list.get(mid) < target) {
                low = mid + 1;
            } else {
                high = mid;
            }
        }
        return low;
    }

    private static int upperBound(List<Integer> list, long target) {
        int low = 0, high = list.size();
        while (low < high) {
            int mid = (low + high) >>> 1;
            if (list.get(mid) <= target) {
                low = mid + 1;
            } else {
                high = mid;
            }
        }
        return low;
    }

    private static long modInverse(long a, long mod) {
        return BigInteger.valueOf(a).modInverse(BigInteger.valueOf(mod)).longValue();
    }

    public static long solve(long[] nums, long[][] queries) {
        int n = nums.length;
        int q = queries.length;
        int B = (int) Math.sqrt(n);

        List<Integer>[][] residueLists = new ArrayList[B + 1][];
        for (int k = 1; k <= B; k++) {
            residueLists[k] = new ArrayList[k];
            for (int r = 0; r < k; r++) {
                residueLists[k][r] = new ArrayList<>();
            }
        }

        for (int i = 0; i < n; i++) {
            for (int k = 1; k <= B; k++) {
                int r = i % k;
                residueLists[k][r].add(i);
            }
        }

        long[][][] factorsArray = new long[B + 1][][];
        for (int k = 1; k <= B; k++) {
            factorsArray[k] = new long[k][];
            for (int r = 0; r < k; r++) {
                int len = residueLists[k][r].size();
                factorsArray[k][r] = new long[len + 1];
                Arrays.fill(factorsArray[k][r], 1);
            }
        }

        List<long[]> largeQueries = new ArrayList<>();

        for (int idx = 0; idx < q; idx++) {
            long[] query = queries[idx];
            long li = query[0];
            long ri = query[1];
            long ki = query[2];
            long vi = query[3];

            if (ki <= B) {
                int k = (int) ki;
                int r0 = (int) (li % ki);
                List<Integer> list = residueLists[k][r0];
                int leftIndex = lowerBound(list, li);
                int rightIndex = upperBound(list, ri) - 1;

                if (leftIndex <= rightIndex) {
                    factorsArray[k][r0][leftIndex] = (factorsArray[k][r0][leftIndex] * vi) % mod;
                    int next = rightIndex + 1;
                    long invVi = modInverse(vi, mod);
                    factorsArray[k][r0][next] = (factorsArray[k][r0][next] * invVi) % mod;
                }
            } else {
                largeQueries.add(query);
            }
        }

        for (int k = 1; k <= B; k++) {
            for (int r = 0; r < k; r++) {
                List<Integer> list = residueLists[k][r];
                long[] factors = factorsArray[k][r];
                long current = 1;
                for (int j = 0; j < list.size(); j++) {
                    current = (current * factors[j]) % mod;
                    int index = list.get(j);
                    nums[index] = (nums[index] * current) % mod;
                }
            }
        }

        for (long[] query : largeQueries) {
            long li = query[0];
            long ri = query[1];
            long ki = query[2];
            long vi = query[3];
            for (long idx = li; idx <= ri; idx += ki) {
                int index = (int) idx;
                nums[index] = (nums[index] * vi) % mod;
            }
        }

        long res = 0;
        for (long num : nums) {
            res ^= num;
        }
        return res;
    }
}
