import java.util.*;

public class Solution {
    private static final long MOD = 1000000007L;

    public static long solve(long[] nums, long[][] queries) {
        int n = nums.length;
        int SQRT = (int) Math.sqrt(n) + 1;

        long[] result = new long[n];
        for (int i = 0; i < n; i++) {
            result[i] = nums[i];
        }

        List<long[]>[][] smallEvents = new ArrayList[SQRT][];
        for (int kk = 1; kk < SQRT; kk++) {
            smallEvents[kk] = new ArrayList[kk];
            for (int r = 0; r < kk; r++) {
                smallEvents[kk][r] = new ArrayList<>();
            }
        }

        for (long[] q : queries) {
            long l = q[0];
            long r_bound = q[1];
            long k = q[2];
            long v = q[3];
            if (k >= SQRT) {
                int start = (int) l;
                int end = (int) r_bound;
                int step = (int) k;
                for (int idx = start; idx <= end; idx += step) {
                    result[idx] = (result[idx] * v) % MOD;
                }
            } else {
                int kk = (int) k;
                if (kk == 0) continue;
                int residue = (int) (l % kk);
                if (r_bound < residue) {
                    continue;
                }
                long j_start = (l - residue) / kk;
                long j_end = (r_bound - residue) / kk;
                if (kk < SQRT) {
                    smallEvents[kk][residue].add(new long[]{j_start, j_end, v});
                }
            }
        }

        for (int kk = 1; kk < SQRT; kk++) {
            for (int residue = 0; residue < kk; residue++) {
                List<long[]> events = smallEvents[kk][residue];
                if (events.isEmpty()) continue;
                int max_j = (n - 1 - residue) / kk;
                long[] diff = new long[max_j + 2];
                for (int i = 0; i < diff.length; i++) {
                    diff[i] = 1;
                }
                for (long[] event : events) {
                    long j_start = event[0];
                    long j_end = event[1];
                    long v_val = event[2];
                    if (j_start > max_j) continue;
                    long actual_end = Math.min(j_end, max_j);
                    int s_idx = (int) j_start;
                    int e_idx = (int) actual_end;
                    diff[s_idx] = (diff[s_idx] * v_val) % MOD;
                    if (e_idx + 1 < diff.length) {
                        long inv = modInverse(v_val, MOD);
                        diff[e_idx + 1] = (diff[e_idx + 1] * inv) % MOD;
                    }
                }
                long[] factors = new long[max_j + 1];
                long cur = 1;
                for (int j = 0; j <= max_j; j++) {
                    cur = (cur * diff[j]) % MOD;
                    factors[j] = cur;
                }
                for (int j = 0; j <= max_j; j++) {
                    int idx = residue + j * kk;
                    if (idx < n) {
                        result[idx] = (result[idx] * factors[j]) % MOD;
                    }
                }
            }
        }

        long xor = 0;
        for (long num : result) {
            xor ^= num;
        }
        return xor;
    }

    private static long modInverse(long a, long modulus) {
        return power(a, modulus - 2, modulus);
    }

    private static long power(long base, long exponent, long modulus) {
        base %= modulus;
        long result = 1;
        while (exponent > 0) {
            if ((exponent & 1) == 1) {
                result = (result * base) % modulus;
            }
            base = (base * base) % modulus;
            exponent >>= 1;
        }
        return result;
    }
